+function Get-VorceStudiosAutonomousAdapterTargetsByRoleKey {
+    param(
+        [Parameter(Mandatory)][hashtable]$Availability
+    )
+
+    $targets = [ordered]@{}
+    $qwenAvailable = [bool](Get-VorceStudiosObjectPropertyValue -Object (Get-VorceStudiosObjectPropertyValue -Object $Availability -PropertyName 'qwen') -PropertyName 'available')
+    $geminiAvailable = [bool](Get-VorceStudiosObjectPropertyValue -Object (Get-VorceStudiosObjectPropertyValue -Object $Availability -PropertyName 'gemini') -PropertyName 'available')
+    $codexAvailable = [bool](Get-VorceStudiosObjectPropertyValue -Object (Get-VorceStudiosObjectPropertyValue -Object $Availability -PropertyName 'codex') -PropertyName 'available')
+
+    foreach ($roleKey in $CodexPrimaryRoleKeys) {
+        $targets[$roleKey] = if ($codexAvailable) {
+            New-VorceStudiosCodexLocalTarget -TimeoutSec 900 -Search:($roleKey -eq 'ceo') -ReasoningEffort 'xhigh'
+        } elseif ($qwenAvailable) {
+            New-VorceStudiosQwenProcessTarget -TimeoutSec 900
+        } else {
+            New-VorceStudiosGeminiLocalTarget -TimeoutSec 900
+        }
+    }
+
+    foreach ($roleKey in $QwenPrimaryRoleKeys) {
+        $targets[$roleKey] = if ($qwenAvailable) {
+            New-VorceStudiosQwenProcessTarget -TimeoutSec 600
+        } elseif ($codexAvailable) {
+            New-VorceStudiosCodexLocalTarget -TimeoutSec 600 -ReasoningEffort 'medium'
+        } else {
+            New-VorceStudiosGeminiLocalTarget -TimeoutSec 600
+        }
+    }
+
+    foreach ($roleKey in $GeminiPreferredRoleKeys) {
+        $targets[$roleKey] = if ($geminiAvailable) {
+            New-VorceStudiosGeminiLocalTarget -TimeoutSec $(if ($roleKey -eq 'antigravity') { 900 } else { 600 })
+        } elseif ($qwenAvailable) {
+            New-VorceStudiosQwenProcessTarget -TimeoutSec $(if ($roleKey -eq 'antigravity') { 900 } else { 600 })
+        } else {
+            New-VorceStudiosCodexLocalTarget -TimeoutSec $(if ($roleKey -eq 'antigravity') { 900 } else { 600 }) -ReasoningEffort 'high'
         }
     }
+
+    return $targets
 }
