+function Test-VorceStudiosVendorPluginNeedsBuild {
+    param(
+        [Parameter(Mandatory)][hashtable]$Definition
+    )
+
+    if (-not (Test-VorceStudiosVendorPluginBuildReady -Definition $Definition)) {
+        return $true
+    }
+
+    $localPath = [string]$Definition.LocalPath
+    $distLatest = Get-VorceStudiosLatestFileTimestamp -Path (Join-Path $localPath 'dist')
+    if ($null -eq $distLatest) {
+        return $true
+    }
+
+    if ([string]$Definition.PluginId -eq 'paperclip-plugin-telegram') {        
+        $srcWorkerPath = Join-Path $localPath 'src\worker.ts'
+        $distWorkerPath = Join-Path $localPath 'dist\worker.js'
+        if ((Test-Path -LiteralPath $srcWorkerPath) -and (Test-Path -LiteralPath $distWorkerPath)) {
+            $srcWorker = Get-Content -LiteralPath $srcWorkerPath -Raw -ErrorAction Stop
+            $distWorker = Get-Content -LiteralPath $distWorkerPath -Raw -ErrorAction Stop
+            if (($srcWorker -match 'registerUnconfiguredTelegramHandlers') -and ($distWorker -notmatch 'telegram_not_configured')) {
+                return $true
+            }
+        }
+    }
+
+    $sourceCandidates = @(
+        (Join-Path $localPath 'src'),
+        (Join-Path $localPath 'public'),
+        (Join-Path $localPath 'templates'),
+        (Join-Path $localPath 'package.json'),
+        (Join-Path $localPath 'esbuild.config.mjs'),
+        (Join-Path $localPath 'rollup.config.mjs'),
+        (Join-Path $localPath 'scripts')
+    )
+
+    foreach ($candidate in $sourceCandidates) {
+        if (-not (Test-Path -LiteralPath $candidate)) {
+            continue
+        }
+
+        $latest = if ((Get-Item -LiteralPath $candidate).PSIsContainer) {      
+            Get-VorceStudiosLatestFileTimestamp -Path $candidate
+        } else {
+            [datetime](Get-Item -LiteralPath $candidate).LastWriteTimeUtc      
+        }
+
+        if ($null -ne $latest -and $latest -gt $distLatest) {
+            return $true
+        }
+    }
+
+    return $false
+}
