+
+                foreach ($propertyName in @('id', 'pluginKey', 'packageName')) {
+                    $value = [string](Get-VorceStudiosObjectPropertyValue -Object $plugin -PropertyName $propertyName)
+                    if (-not [string]::IsNullOrWhiteSpace($value) -and $value -eq [string]$candidate) {
+                        $matched = $true
+                        break
+                    }
+                }
+
+                if ($matched) {
+                    break
+                }
+            }
+
+            $matched
+        } |
+        Select-Object -First 1
+}
+
+function Ensure-VorceStudiosVendorPluginInstalled {
+    param(
+        [Parameter(Mandatory)][string]$Name,
+        [switch]$Enable
+    )
+
+    $definition = Get-VorceStudiosPluginSourceDefinition -PluginId $Name       
+    if ($null -eq $definition) {
+        throw "Plugin '$Name' ist nicht definiert."
+    }
+
+    $prepare = Ensure-VorceStudiosVendorPluginPrepared -Name $Name
+    $existing = Find-VorceStudiosPluginForVendor -Definition $definition       
+    $upgrade = $null
+    $plugin = $existing
+
+    if ($null -eq $existing) {
+        $plugin = Install-VorceStudiosPlugin -PackageName $prepare.localPath -IsLocalPath
+    } elseif ($prepare.built -or $prepare.dependenciesInstalled) {
+        try {
+            $upgrade = Upgrade-VorceStudiosPlugin -PluginId ([string]$existing.id)
+        } catch {
+            $upgrade = Refresh-VorceStudiosVendorPlugin -PluginId ([string]$definition.PluginId) -LocalPath $prepare.localPath -InstalledPlugin $existing -Reasons @('upgrade_failed')
+        }
+
+        Start-Sleep -Milliseconds 500
+        $plugin = Find-VorceStudiosPluginForVendor -Definition $definition     
+    }
+
+    if ($Enable.IsPresent -and $null -ne $plugin) {
+        $pluginId = [string](Get-VorceStudiosObjectPropertyValue -Object $plugin -PropertyName 'id')
+        if (-not [string]::IsNullOrWhiteSpace($pluginId)) {
+            $status = [string](Get-VorceStudiosObjectPropertyValue -Object $plugin -PropertyName 'status')
+            if ($status -ne 'ready') {
+                Enable-VorceStudiosPlugin -PluginId $pluginId | Out-Null       
+                Start-Sleep -Milliseconds 250
+                $plugin = Find-VorceStudiosPluginForVendor -Definition $definition
+            }
+        }
+    }
+
+    return [ordered]@{
+        source = $definition
+        prepare = $prepare
+        upgrade = $upgrade
+        plugin = $plugin
+    }
+}
