 }
+
+function Get-VorceStudiosPaperclipProcessCandidates {
+    $paths = Get-VorceStudiosPaths
+    $system = Get-VorceStudiosSystemPolicy
+    $escapedRunner = [regex]::Escape((Join-Path $paths.Root 'ops\paperclip\Run-Vorce-StudiosPaperclip.ps1'))
+    $escapedConfig = [regex]::Escape((Join-Path $paths.Root '.paperclip\config.json'))
+    $escapedHome = [regex]::Escape((Join-Path $paths.Root '.paperclip-home'))  
+    $escapedVendorWorkers = [regex]::Escape((Join-Path $paths.Root '.paperclip-home\vendor-plugins\paperclip-plugin-'))
+    $version = [regex]::Escape([string]$system.Company.PaperclipVersion)       
+
+    return @(
+        Get-CimInstance Win32_Process -ErrorAction SilentlyContinue |
+            Where-Object {
+                $commandLine = [string]$_.CommandLine
+                if ([string]::IsNullOrWhiteSpace($commandLine)) {
+                    return $false
+                }
+
+                return (
+                    ($commandLine -match $escapedRunner) -or
+                    ($commandLine -match "paperclipai@$version") -or
+                    (($commandLine -match $escapedConfig) -and ($commandLine -match $escapedHome)) -or
+                    ($commandLine -match $escapedVendorWorkers)
+                )
+            }
+    )
+}
+
+function Get-VorceStudiosPaperclipProcesses {
+    $system = Get-VorceStudiosSystemPolicy
+    $processState = Get-VorceStudiosProcessState
+    $seedIds = New-Object System.Collections.Generic.HashSet[int]
+
+    foreach ($entryName in @('paperclip', 'supervisor')) {
+        $entry = $processState[$entryName]
+        if ($entry -is [System.Collections.IDictionary] -and $entry.ContainsKey('pid')) {
+            $resolvedPid = 0
+            if ([int]::TryParse([string]$entry['pid'], [ref]$resolvedPid) -and $resolvedPid -gt 0 -and $resolvedPid -ne $PID) {
+                $seedIds.Add($resolvedPid) | Out-Null
+            }
+        }
+    }
+
+    foreach ($port in @([int]$system.Company.ServerPort, [int]$system.Company.DatabasePort)) {
+        try {
+            foreach ($connection in @(Get-NetTCPConnection -LocalPort $port -State Listen -ErrorAction Stop)) {
+                if ($connection.OwningProcess -gt 0 -and $connection.OwningProcess -ne $PID) {
+                    $seedIds.Add([int]$connection.OwningProcess) | Out-Null    
+                }
+            }
+        } catch {
+        }
+    }
+
+    $allProcesses = @(Get-CimInstance Win32_Process -ErrorAction SilentlyContinue)
+    foreach ($candidate in @(Get-VorceStudiosPaperclipProcessCandidates)) {    
+        if ($candidate.ProcessId -gt 0 -and $candidate.ProcessId -ne $PID) {   
+            $seedIds.Add([int]$candidate.ProcessId) | Out-Null
+        }
+    }
+
+    $queue = New-Object System.Collections.Generic.Queue[int]
+    foreach ($seedId in $seedIds) {
+        $queue.Enqueue($seedId)
+    }
+
+    $visited = New-Object System.Collections.Generic.HashSet[int]
+    while ($queue.Count -gt 0) {
+        $currentId = $queue.Dequeue()
+        if (-not $visited.Add($currentId)) {
+            continue
+        }
+
+        foreach ($child in @($allProcesses | Where-Object { [int]$_.ParentProcessId -eq $currentId })) {
+            if ($child.ProcessId -gt 0 -and $child.ProcessId -ne $PID) {       
+                $queue.Enqueue([int]$child.ProcessId)
+            }
+        }
+    }
+
+    return @(
+        $allProcesses |
+            Where-Object { $visited.Contains([int]$_.ProcessId) } |
+            Sort-Object ParentProcessId, ProcessId |
+            ForEach-Object {
+                [ordered]@{
+                    pid = [int]$_.ProcessId
+                    parentPid = [int]$_.ParentProcessId
+                    name = [string]$_.Name
+                    executablePath = [string]$_.ExecutablePath
+                    commandLine = [string]$_.CommandLine
+                }
+            }
+    )
+}
+
+function Stop-VorceStudiosPaperclipProcesses {
+    $targets = @(Get-VorceStudiosPaperclipProcesses)
+    $stopped = New-Object System.Collections.Generic.List[object]
+
+    foreach ($target in @($targets | Sort-Object parentPid, pid -Descending)) {
+        try {
+            Stop-Process -Id ([int]$target.pid) -Force -ErrorAction Stop       
+            $stopped.Add([ordered]@{
+                pid = [int]$target.pid
+                name = [string]$target.name
+                status = 'stopped'
+            }) | Out-Null
+        } catch {
+            $stopped.Add([ordered]@{
+                pid = [int]$target.pid
+                name = [string]$target.name
+                status = 'missing'
+                error = $_.Exception.Message
+            }) | Out-Null
+        }
+    }
+
+    return @($stopped.ToArray())
+}
